"""Generate the capybara-onsen patch package from scene data and a target Claude Code binary.

The art data is compiled by the neighboring scene scripts. This emitter wraps
that data in the current responsive renderer patch structure and computes the
source/module identity from the requested binary at generation time.
"""
from __future__ import annotations

import argparse
import json
import os
import sys
from pathlib import Path

