# Trigger phrases for the pool-hop scene change. Case-insensitive substring
# match against assistant message text. Edit here and regenerate.
#
# Note: __coSoak.seen (in HELPER_TEMPLATE's __coOnAssistantText) grows one
# entry per assistant message id for the lifetime of the session -- an
# accepted tradeoff for the streaming-safe trigger-count dedup, not a bug.
TRIGGER_PHRASES = [
    "hopping in the pool",
    "hop in the pool",
    "hopping into the pool",
]

# Injected into the conversation when the capybara hops in, as a
# hidden-context attachment row: ki({type:"critical_system_reminder",...}).
# The note is now assembled at hop time (__coCapyPostcard()) from live state:
# a lead line, a pre-baked ASCII scene strip picked by the current active pup
# count with one `(o.o)` per pup, an optional `with: <name>, <name>` line
# naming up to 3 pups' real Task-tool descriptions, and a close line. Only the
# lead/close prose are static Python constants; the scene and names are
# runtime-computed from __coPups.active. Invisible in the stock UI (Ypr
# filters scf-set attachment types before the row renderer), surfaced
# automatically by hidden-context-inline (inline) or
# hidden-context-drawer (footer drawer) via their existing
# critical_system_reminder projection branches — no capy-specific code in
# either — and forwarded to model context by ARc as an isMeta user message
# wrapped in <system-reminder> tags. Survives /resume (not in the
# deserialize-time drop-set). See tests/test_pool_hop_composition.py.
CAPY_NOTE_LEAD = "\U0001F439 You've hopped into the onsen pool!"
CAPY_NOTE_CLOSE = "Enjoy the break, CapyClaude~"

# By-name dependencies of the subagent-pup runtime on Claude Code 2.1.201
# internals (store getter + AppState.tasks record shape). No replace_exact op
# consumes these -- payload 01 calls Rc() by name -- so the emitter's anchor
# verification never sees them. This guard makes a future rename fail loudly
# at generation time instead of shipping a silently-degraded patch.
# Each string must occur exactly once in the target module.
#
# Note: the fourth anchor below is a longer variant than
# `type:"local_agent",status:"running"` -- that shorter literal occurs 3x in
# 2.1.201 (three separate task-record constructors share the same shape).
# This is the construction site for Task-tool subagents specifically (params
# include ownerAgentId/parentAgentId/spawnDepth/taskRegistry/
# parentAbortController), extended until unique (verified count==1 the same
# way as the others).
RUNTIME_IDENTITY_ANCHORS = [
    'function Rc(){return sio()}',
    'function sio(){let e=lPe.useContext(idt);',
    'return{settings:Hr(),tasks:{},transcripts:{}',
    'type:"local_agent",status:"running",agentId:e,ownerAgentId:t,parentAgentId:n,spawnDepth:r,prompt:s,cwd:u,selectedAgent:i,agentType:i.agentType??"general-purpose",abortController:d,retrieved:!1,lastReportedToolCount:0,lastReportedTokenCount:0,isBackgrounded:!0',
]


def _resolve_source_like_emitter() -> Path:
    """Resolve the target binary the exact way emit_package() will.

    Mirrors art_package_emitter.source_from_args()'s source resolution
    (examples/art_package_emitter.py lines 89-93): args.source (accepting
    both `--source VALUE` and `--source=VALUE`, since argparse parses both
    forms identically) or the HM_GENERATE_SOURCE env var, else
    newest_local_source(). Precedence: --source > HM_GENERATE_SOURCE >
    newest_local_source(). We only need the resolved path (not version/
    version_out), so we stop short of source_from_args() itself, which also
    shells out to the binary for `--version` when no explicit version output
    is given -- a side effect we don't want just to check identity.
    """
    from art_package_emitter import newest_local_source
    parser = argparse.ArgumentParser()
    parser.add_argument("--source")
    parser.add_argument("--source-version")
    parser.add_argument("--source-version-output")
    args, _unknown = parser.parse_known_args(sys.argv[1:])
    source_arg = args.source or os.environ.get("HM_GENERATE_SOURCE")
    source = Path(source_arg).expanduser() if source_arg else newest_local_source()
    if not source.exists():
        raise SystemExit(f"source does not exist: {source}")
    return source


def _check_runtime_identity_anchors() -> None:
    from art_package_emitter import module_content
    source = _resolve_source_like_emitter()
    module = module_content(source.read_bytes()).decode('utf-8')
    bad = [(a, module.count(a)) for a in RUNTIME_IDENTITY_ANCHORS if module.count(a) != 1]
    if bad:
        raise SystemExit(
            f'runtime identity anchors not unique in {source}: {bad!r} -- '
            're-derive the Rc/AppState.tasks seams for this Claude Code version '
            '(see docs/superpowers/specs/2026-07-05-subagent-capybaras-monitoring-design.md)'
        )


